// Simplified lightweight Compare component without external particle deps
const Compare = ({ firstImage, secondImage, className }: { firstImage?: string | null, secondImage?: string | null, className?: string }) => {
    const [sliderPosition, setSliderPosition] = useState(50);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isDragging, setIsDragging] = useState(false);

    const handleMove = (clientX: number) => {
        if (!containerRef.current) return;
        const rect = containerRef.current.getBoundingClientRect();
        const x = Math.max(0, Math.min(clientX - rect.left, rect.width));
        setSliderPosition((x / rect.width) * 100);
    };

    const handleTouchMove = (e: React.TouchEvent) => handleMove(e.touches[0].clientX);
    const handleMouseMove = (e: React.MouseEvent) => { if (isDragging) handleMove(e.clientX); };

    return (
        <div 
            ref={containerRef}
            className={cn("relative overflow-hidden cursor-ew-resize select-none", className)}
            onMouseDown={() => setIsDragging(true)}
            onMouseUp={() => setIsDragging(false)}
            onMouseLeave={() => setIsDragging(false)}
            onMouseMove={handleMouseMove}
            onTouchMove={handleTouchMove}
            onClick={(e) => handleMove(e.clientX)}
        >
             {secondImage && <img src={secondImage} alt="After" className="absolute inset-0 w-full h-full object-cover" />}
             {firstImage && (
                 <div 
                    className="absolute inset-0 w-full h-full overflow-hidden" 
                    style={{ clipPath: `inset(0 ${100 - sliderPosition}% 0 0)` }}
                 >
                     <img src={firstImage} alt="Before" className="absolute inset-0 w-full h-full object-cover max-w-none" />
                 </div>
             )}
             <div 
                className="absolute top-0 bottom-0 w-1 bg-white cursor-ew-resize shadow-[0_0_10px_rgba(0,0,0,0.5)] z-20 flex items-center justify-center"
                style={{ left: `${sliderPosition}%`, transform: 'translateX(-50%)' }}
             >
                 <div className="w-8 h-8 bg-white rounded-full shadow-lg flex items-center justify-center">
                    <Icons.DotsVertical className="w-4 h-4 text-gray-600" />
                 </div>
             </div>
        </div>
    );
};

