const FitCheckTool: React.FC = () => {
  const [modelImageUrl, setModelImageUrl] = useState<string | null>(null);
  const [outfitHistory, setOutfitHistory] = useState<OutfitLayer[]>([]);
  const [currentOutfitIndex, setCurrentOutfitIndex] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [currentPoseIndex, setCurrentPoseIndex] = useState(0);
  const [isSheetCollapsed, setIsSheetCollapsed] = useState(false);
  const [wardrobe, setWardrobe] = useState<WardrobeItem[]>(defaultWardrobe);

  // Media query hook inline
  const useMediaQuery = (query: string) => {
      const [matches, setMatches] = useState(false);
      useEffect(() => {
          const media = window.matchMedia(query);
          if (media.matches !== matches) setMatches(media.matches);
          const listener = () => setMatches(media.matches);
          media.addEventListener('change', listener);
          return () => media.removeEventListener('change', listener);
      }, [matches, query]);
      return matches;
  }
  const isMobile = useMediaQuery('(max-width: 767px)');

  const activeOutfitLayers = useMemo(() => outfitHistory.slice(0, currentOutfitIndex + 1), [outfitHistory, currentOutfitIndex]);
  const activeGarmentIds = useMemo(() => activeOutfitLayers.map(layer => layer.garment?.id).filter(Boolean) as string[], [activeOutfitLayers]);

  const displayImageUrl = useMemo(() => {
    if (outfitHistory.length === 0) return modelImageUrl;
    const currentLayer = outfitHistory[currentOutfitIndex];
    if (!currentLayer) return modelImageUrl;
    const poseInstruction = POSE_INSTRUCTIONS[currentPoseIndex];
    return currentLayer.poseImages[poseInstruction] ?? Object.values(currentLayer.poseImages)[0];
  }, [outfitHistory, currentOutfitIndex, currentPoseIndex, modelImageUrl]);

  const handleModelFinalized = (url: string) => {
    setModelImageUrl(url);
    setOutfitHistory([{ garment: null, poseImages: { [POSE_INSTRUCTIONS[0]]: url } }]);
    setCurrentOutfitIndex(0);
  };

  const handleStartOver = () => {
    setModelImageUrl(null);
    setOutfitHistory([]);
    setCurrentOutfitIndex(0);
    setIsLoading(false);
    setLoadingMessage('');
    setError(null);
    setCurrentPoseIndex(0);
    setWardrobe(defaultWardrobe);
  };

  const handleGarmentSelect = useCallback(async (garmentFile: File, garmentInfo: WardrobeItem) => {
    if (!displayImageUrl || isLoading) return;
    const nextLayer = outfitHistory[currentOutfitIndex + 1];
    if (nextLayer && nextLayer.garment?.id === garmentInfo.id) {
        setCurrentOutfitIndex(prev => prev + 1);
        setCurrentPoseIndex(0);
        return;
    }
    setError(null);
    setIsLoading(true);
    setLoadingMessage(`Adding ${garmentInfo.name}...`);
    try {
      const newImageUrl = await generateVirtualTryOnImage(displayImageUrl, garmentFile);
      const currentPoseInstruction = POSE_INSTRUCTIONS[currentPoseIndex];
      const newLayer: OutfitLayer = { garment: garmentInfo, poseImages: { [currentPoseInstruction]: newImageUrl } };
      setOutfitHistory(prev => [...prev.slice(0, currentOutfitIndex + 1), newLayer]);
      setCurrentOutfitIndex(prev => prev + 1);
      setWardrobe(prev => prev.find(item => item.id === garmentInfo.id) ? prev : [...prev, garmentInfo]);
    } catch (err) {
      setError(getFriendlyErrorMessage(err, 'Failed to apply garment'));
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [displayImageUrl, isLoading, currentPoseIndex, outfitHistory, currentOutfitIndex]);

  const handlePoseSelect = useCallback(async (newIndex: number) => {
    if (isLoading || outfitHistory.length === 0 || newIndex === currentPoseIndex) return;
    const poseInstruction = POSE_INSTRUCTIONS[newIndex];
    const currentLayer = outfitHistory[currentOutfitIndex];
    if (currentLayer.poseImages[poseInstruction]) {
      setCurrentPoseIndex(newIndex);
      return;
    }
    const baseImage = Object.values(currentLayer.poseImages)[0];
    setError(null);
    setIsLoading(true);
    setLoadingMessage(`Changing pose...`);
    const prevPoseIndex = currentPoseIndex;
    setCurrentPoseIndex(newIndex);
    try {
      const newImageUrl = await generatePoseVariation(baseImage, poseInstruction);
      setOutfitHistory(prev => {
        const newHistory = [...prev];
        newHistory[currentOutfitIndex].poseImages[poseInstruction] = newImageUrl;
        return newHistory;
      });
    } catch (err) {
      setError(getFriendlyErrorMessage(err, 'Failed to change pose'));
      setCurrentPoseIndex(prevPoseIndex);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [currentPoseIndex, outfitHistory, isLoading, currentOutfitIndex]);

  const viewVariants = {
    initial: { opacity: 0, y: 15 },
    animate: { opacity: 1, y: 0 },
    exit: { opacity: 0, y: -15 },
  };

  return (
    <div className="font-sans w-full h-full bg-white text-gray-900">
      <AnimatePresence mode="wait">
        {!modelImageUrl ? (
          <motion.div key="start-screen" className="w-full h-full min-h-screen flex items-center justify-center bg-gray-50 p-4" variants={viewVariants} initial="initial" animate="animate" exit="exit">
            <StartScreen onModelFinalized={handleModelFinalized} />
          </motion.div>
        ) : (
          <motion.div key="main-app" className="relative flex flex-col h-screen overflow-hidden" variants={viewVariants} initial="initial" animate="animate" exit="exit">
            <header className="w-full py-4 px-8 bg-white border-b flex items-center gap-3">
                 <Icons.Shirt className="w-6 h-6 text-gray-700" />
                 <h1 className="text-xl font-serif tracking-widest text-gray-800">Virtual Try-On</h1>
            </header>
            <main className="flex-grow relative flex flex-col md:flex-row overflow-hidden">
              <div className="flex-grow bg-white relative">
                <Canvas 
                  displayImageUrl={displayImageUrl}
                  onStartOver={handleStartOver}
                  isLoading={isLoading}
                  loadingMessage={loadingMessage}
                  onSelectPose={handlePoseSelect}
                  poseInstructions={POSE_INSTRUCTIONS}
                  currentPoseIndex={currentPoseIndex}
                />
              </div>
              <aside className={`absolute md:relative bottom-0 right-0 w-full md:w-80 bg-white/95 backdrop-blur border-l border-t md:border-t-0 flex flex-col transition-transform duration-300 ${isSheetCollapsed && isMobile ? 'translate-y-[calc(100%-3rem)]' : ''}`}>
                  {isMobile && <button onClick={() => setIsSheetCollapsed(!isSheetCollapsed)} className="w-full h-8 flex items-center justify-center bg-gray-100">{isSheetCollapsed ? <Icons.ChevronUp /> : <Icons.ChevronDown />}</button>}
                  <div className="p-4 flex-grow overflow-y-auto pb-20">
                    {error && <div className="bg-red-100 text-red-700 p-3 mb-4 rounded text-sm">{error}</div>}
                    <OutfitStack outfitHistory={activeOutfitLayers} onRemoveLastGarment={() => { if(currentOutfitIndex > 0) { setCurrentOutfitIndex(i => i - 1); setCurrentPoseIndex(0); }}} />
                    <WardrobePanel onGarmentSelect={handleGarmentSelect} activeGarmentIds={activeGarmentIds} isLoading={isLoading} wardrobe={wardrobe} />
                  </div>
              </aside>
            </main>
          </motion.div>
        )}
      </AnimatePresence>
      <Footer isOnDressingScreen={!!modelImageUrl} />
    </div>
  );
};

