export default function FlowstateTool() {
  // State
  const [user] = useState<User>({ id: 'guest-user', email: 'guest@flowstate' });
  const [editorState, setEditorState] = useState<EditorState>({
    currentStep: 'upload', generationMode: 'default', uploadedAssets: [], generatedFlatLays: [], selectedFlatLays: [], staticMockup: null, animatedMockup: null,
    animationConfig: { preset: '360 Spin', aspectRatio: '9:16', customPrompt: null, generateStatic: true, generateVideo: true }
  });

  const [isLoading, setIsLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState('');
  const [error, setError] = useState<string|null>(null);
  const [toast, setToast] = useState<string|null>(null);
  const [previewAsset, setPreviewAsset] = useState<Asset|null>(null);
  const [showKeyModal, setShowKeyModal] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Handlers
  const handleUpload = async (files: File[]) => {
    setIsLoading(true); setLoadingMsg("Processing...");
    try {
        const newAssets = await Promise.all(files.map(async f => {
            const { base64, mimeType } = await normalizeImage(f);
            return { id: `up-${Date.now()}-${Math.random()}`, type: 'image', originalFile: { name: f.name, type: mimeType }, originalB64: base64 } as Asset;
        }));
        setEditorState(p => ({ ...p, uploadedAssets: newAssets, currentStep: 'flatlay' }));
    } catch(e: any) { setError(e.message); }
    setIsLoading(false);
  };

  const handleGenerate = async () => {
    if(!editorState.uploadedAssets.length) return;
    setIsLoading(true); setError(null);
    const baseAsset = editorState.uploadedAssets[0];
    const newAssets: Asset[] = [];
    const mode = editorState.generationMode;

    // Helper to generate assets
    const addAsset = (res: GenerationResult, label: string) => {
        newAssets.push({ id: `gen-${Date.now()}-${Math.random()}`, type: 'image', label, originalFile: { name: 'gen.png', type: res.mimeType }, originalB64: res.base64 });
    };

    try {
        if (mode === 'default') {
            setLoadingMsg("Generating 5X Suite...");
            const r1 = await aiService.generateStrictFlatLay(baseAsset.originalB64, baseAsset.originalFile.type, 'strict'); addAsset(r1, "Strict Flat Lay");
            const r2 = await aiService.generateStrict3DMockup([baseAsset.originalB64], baseAsset.originalFile.type, 'strict'); addAsset(r2, "Strict 3D Mockup");
            const r3 = await aiService.generateFlexibleStudioPhoto([baseAsset.originalB64], baseAsset.originalFile.type, 'flexible'); addAsset(r3, "Flexible Photo");
            const r4 = await aiService.generateStrict3DMockup([baseAsset.originalB64], baseAsset.originalFile.type, 'ecommerce'); addAsset(r4, "Ecommerce Mockup");
            const r5 = await aiService.generateFlexibleStudioPhoto([baseAsset.originalB64], baseAsset.originalFile.type, 'luxury'); addAsset(r5, "Luxury Photo");

            // Video
            setLoadingMsg("Generating Video...");
            const op = await aiService.generateFlexibleVideo(baseAsset.originalB64, baseAsset.originalFile.type, 'default');
            const vidAsset = await waitForVideo(op);
            if(vidAsset) { vidAsset.label = "Video"; newAssets.push(vidAsset); }
        } else {
            // Simplified for other modes
            setLoadingMsg(`Generating ${mode} assets...`);
            const r1 = await aiService.generateStrictFlatLay(baseAsset.originalB64, baseAsset.originalFile.type, mode); addAsset(r1, `${mode} Flat Lay`);
            const r2 = await aiService.generateStrict3DMockup([baseAsset.originalB64], baseAsset.originalFile.type, mode); addAsset(r2, `${mode} Mockup`);
            const r1_2 = await aiService.generateStrictFlatLay(baseAsset.originalB64, baseAsset.originalFile.type, mode); addAsset(r1_2, `${mode} Flat Lay 2`);
            const r2_2 = await aiService.generateStrict3DMockup([baseAsset.originalB64], baseAsset.originalFile.type, mode); addAsset(r2_2, `${mode} Mockup 2`);
        }
        setEditorState(p => ({ ...p, generatedFlatLays: newAssets, selectedFlatLays: [] }));
    } catch(e: any) { setError(e.message); if(e.message.includes('Key')) setShowKeyModal(true); }
    setIsLoading(false);
  };

  const waitForVideo = async (op: Operation<GenerateVideosResponse>): Promise<Asset | null> => {
      let operation = op;
      while(!operation.done) { await new Promise(r => setTimeout(r, 5000)); operation = await aiService.checkVideoOperationStatus(operation); }
      const uri = operation.response?.generatedVideos?.[0]?.video?.uri;
      if(uri) {
          const res = await fetch(`${uri}&key=${process.env.API_KEY}`);
          const blob = await res.blob();
          return { id: `vid-${Date.now()}`, type: 'video', originalFile: { name: 'video.mp4', type: 'video/mp4' }, originalB64: '', processedUrl: URL.createObjectURL(blob) };
      }
      return null;
  };

  const handleSelect = (a: Asset) => {
      setEditorState(p => {
          const exists = p.selectedFlatLays.find(x => x.id === a.id);
          return { ...p, selectedFlatLays: exists ? p.selectedFlatLays.filter(x => x.id !== a.id) : [...p.selectedFlatLays, a] };
      });
  };

  // Render logic
  const getAssets = () => {
      if(editorState.currentStep === 'upload') return editorState.uploadedAssets;
      if(editorState.currentStep === 'flatlay') return editorState.generatedFlatLays.length ? editorState.generatedFlatLays : editorState.uploadedAssets;
      const res = []; if(editorState.staticMockup) res.push(editorState.staticMockup); if(editorState.animatedMockup) res.push(editorState.animatedMockup);
      return res.length ? res : editorState.selectedFlatLays;
  };

  return (
    <div className="flex h-screen bg-gray-900 text-gray-100 font-sans overflow-hidden">
      {isLoading && <Loader message={loadingMsg} />}
      {error && <div className="fixed top-4 right-4 bg-red-600 text-white p-3 rounded z-50">{error} <button onClick={()=>setError(null)} className="ml-2 font-bold">x</button></div>}
      {toast && <Toast message={toast} />}
      {showKeyModal && <ApiKeyModal onSelectKey={async () => { await (window as any).aistudio?.openSelectKey(); setShowKeyModal(false); }} />}

      {/* Sidebar */}
      <div className={`${sidebarOpen?'translate-x-0':'-translate-x-full'} md:translate-x-0 transition-transform fixed md:static inset-y-0 left-0 w-80 bg-gray-800 border-r border-gray-700 z-30 flex flex-col`}>
          <div className="p-4 border-b border-gray-700 font-bold text-xl">Flowstate Engine</div>
          <div className="p-4">
              <ModeSelector selectedMode={editorState.generationMode} onChangeMode={(m) => setEditorState(p => ({...p, generationMode: m}))} />

              <div className="space-y-4 mt-4">
                  <div className={`p-3 border-l-4 ${editorState.currentStep==='upload'?'border-blue-500 bg-gray-700/50': 'border-gray-600'}`}>
                      <h3 className="font-bold">1. Upload</h3>
                      {editorState.currentStep==='upload' && <input type="file" onChange={(e)=>e.target.files && handleUpload(Array.from(e.target.files))} className="mt-2 text-sm" />}
                  </div>
                  <div className={`p-3 border-l-4 ${editorState.currentStep==='flatlay'?'border-blue-500 bg-gray-700/50': 'border-gray-600'}`}>
                      <h3 className="font-bold">2. Generate</h3>
                      {editorState.currentStep==='flatlay' && <button onClick={handleGenerate} className="mt-2 w-full bg-blue-600 py-2 rounded font-bold hover:bg-blue-700">Generate Assets</button>}
                      {editorState.generatedFlatLays.length > 0 && <button onClick={() => setEditorState(p => ({...p, currentStep: 'animate'}))} disabled={!editorState.selectedFlatLays.length} className="mt-2 w-full bg-green-600 py-2 rounded font-bold disabled:opacity-50">Next Step &rarr;</button>}
                  </div>
                  {/* Additional steps can be added here */}
              </div>
          </div>
      </div>

      {/* Main Area */}
      <div className="flex-1 flex flex-col p-4 relative">
          <button className="md:hidden absolute top-4 left-4 z-40 bg-gray-800 p-2 rounded" onClick={()=>setSidebarOpen(!sidebarOpen)}>☰</button>
          <Canvas assets={getAssets()} selectedIds={editorState.selectedFlatLays.map(x=>x.id)} onSelect={handleSelect} onPreview={setPreviewAsset} onDownload={(a: Asset) => { const l = document.createElement('a'); l.href = a.type==='video'?a.processedUrl!: `data:${a.originalFile.type};base64,${a.originalB64}`; l.download = a.originalFile.name; l.click(); }} />
      </div>

      {previewAsset && (
        <div className="fixed inset-0 bg-black/95 z-[70] flex items-center justify-center p-4">
            <button className="absolute top-4 right-4 text-white text-2xl" onClick={()=>setPreviewAsset(null)}>✕</button>
            {previewAsset.type==='video' ? <video src={previewAsset.processedUrl} controls className="max-h-full" /> : <img src={`data:${previewAsset.originalFile.type};base64,${previewAsset.originalB64}`} className="max-h-full" />}
        </div>
      )}
    </div>
  );
}

