                                       <button type="button" key={opt} onClick={() => { setPrompt(p => p + (p ? ', ' : '') + opt); }} className="text-left text-xs hover:text-[#FFC20E] truncate">{opt}</button>
                                   ))}
                               </div>
                           </div>
                       ))}
                   </div>
               </div>
           )}
        </div>

        <div className="grid grid-cols-2 gap-2">
            {STYLES.map((s) => (
              <button key={s.id} type="button" onClick={() => setStyle(s.id)} className={`flex items-center gap-2 px-3 py-2 rounded-lg border text-xs text-left transition-all ${style === s.id ? 'bg-[#FFC20E] text-black border-[#FFC20E] font-bold' : 'border-[#27272a] text-gray-400 hover:border-gray-500'}`}>
                {getIcon(s.icon)} {s.id}
              </button>
            ))}
        </div>

        <div className="flex gap-2">
           <select value={ratio} onChange={(e) => setRatio(e.target.value as AspectRatio)} className="flex-1 bg-black/30 border border-[#27272a] rounded-lg text-xs text-white p-2"><option value="1:1">1:1</option><option value="9:16">9:16</option></select>
           <select value={resolution} onChange={(e) => setResolution(e.target.value as Resolution)} className="flex-1 bg-black/30 border border-[#27272a] rounded-lg text-xs text-white p-2"><option value="4K">4K</option></select>
        </div>

        <button type="submit" disabled={isLoading} className="w-full bg-[#FFC20E] text-black h-12 rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-[#e6af0b] transition-all">
          {isLoading ? 'Generating...' : 'GENERATE MOCKUPS'}
        </button>
      </form>
    </div>
  );
};

